import React, { useState, useEffect } from 'react';
import { View, Text, Button, AsyncStorage } from 'react-native';
import Biometric from 'react-native-biometrics';

const App = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  useEffect(() => {
    checkBiometry();
  }, []);

  const checkBiometry = async () => {
    try {
      const isAvailable = await Biometric.isEnrolled();
      if (isAvailable) {
        const result = await Biometric.verify();
        if (result.success) {
          storeAuthenticatedFlag(true);
        } else {
          console.log('Authentication failed');
        }
      } else {
        console.log('Biometry not available');
      }
    } catch (error) {
      console.error(error);
    }
  };

  const storeAuthenticatedFlag = async (flag) => {
    try {
      await AsyncStorage.setItem('isAuthenticated', flag.toString());
      setIsAuthenticated(flag);
    } catch (error) {
      console.error(error);
    }
  };

  const loginScreen = () => {
    return (
      <View>
        <Text>Login Screen</Text>
        <Button title="Login" onPress={() => checkBiometry()} />
      </View>
    );
  };

  const mainScreen = () => {
    if (isAuthenticated) {
      return (
        <View>
          <Text>Main Screen</Text>
          <Button title="Logout" onPress={() => logout()} />
        </View>
      );
    } else {
      return loginScreen();
    }
  };

  const logout = async () => {
    try {
      await AsyncStorage.removeItem('isAuthenticated');
      setIsAuthenticated(false);
    } catch (error) {
      console.error(error);
    }
  };

  return mainScreen();
};

export default App;